var e=[{id:`L3_1`,type:`dialog`,speaker:`SAW_REAPER_NULL_CODENAME`,text:{KOREA:`읏샤- 이걸로 전부 처리 완료.`,JPN:`よっしゃー、これで処理は完了。`,ENG:`Phew! And that's that.`,TWN:`呼——這下就結束了吧？`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SAW_REAPER_NULL_CODENAME`,face:`UNIT_PRIDE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SAW_REAPER_NULL_CODENAME`,text:{KOREA:`다들 괜찮으세요?`,JPN:`みなさん、大丈夫ですか？`,ENG:`Is everyone okay?`,TWN:`大家還好嗎？`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SAW_REAPER_NULL_CODENAME`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`EXOSUIT_FLOOR_NULL_TEAM3`,text:{KOREA:`너…`,JPN:`お前……`,ENG:`You...`,TWN:`你……`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EXOSUIT_FLOOR_NULL_TEAM3`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`EXOSUIT_FLOOR_NULL_TEAM3`,text:{KOREA:`대체 어디 숨어있다가 이제야 기어 나온 거야!`,JPN:`いったい今までどこにいやがったんだ！`,ENG:`Where have you been hiding all this time?!`,TWN:`你到底躲到哪裡去了，怎麼現在才來！`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EXOSUIT_FLOOR_NULL_TEAM3`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`SAW_REAPER_NULL_CODENAME`,text:{KOREA:`무전을 보내도 답신이 없더라고요.`,JPN:`無線を送っても返答がなかったんですよ。`,ENG:`I tried sending a transmission, but all I got was radio silence.`,TWN:`我發了無線電呼叫，但沒有人回覆。`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SAW_REAPER_NULL_CODENAME`,face:`UNIT_LAUGH`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`SAW_REAPER_NULL_CODENAME`,text:{KOREA:`함부로 움직이면 엇갈릴까 봐 기다리고 있었어요.`,JPN:`むやみに動くとすれ違ってしまいそうなので、待っていたんです。`,ENG:`I stayed put so we didn't go looking for each other the wrong way.`,TWN:`我怕亂走的話會錯過你們，就一直在這裡等著。`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SAW_REAPER_NULL_CODENAME`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SAW_REAPER_NULL_CODENAME`,text:{KOREA:`목소리가 들려서 와봤는데, 너무 늦지 않아서 다행이네요!`,JPN:`声がしたので来てみたんですが、遅すぎなかったみたいでよかったです！`,ENG:`I came here because I heard voices. Good thing I wasn't too late!`,TWN:`剛剛聽到聲音，我就過來了，幸好不算太晚！`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SAW_REAPER_NULL_CODENAME`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`EXOSUIT_FLOOR_NULL_TEAM3`,text:{KOREA:`그걸 말이라고 해? 너 하나 찾으려다 우린 전부 몰살당할 뻔했다고!`,JPN:`おい、何言ってんだ！　お前のせいで俺たちは全滅するところだったんだぞ！`,ENG:`Are you kidding me? We all almost died trying to find you!`,TWN:`什麼不晚？我們差點因為找你被殺掉了！`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`EXOSUIT_FLOOR_NULL_TEAM3`,face:`UNIT_IDLE`},C:null,R:{char_id:`SAW_REAPER_NULL_CODENAME`,face:`UNIT_SURPRISE`}}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`},{id:`L13_1`,type:`dialog`,speaker:`SAW_REAPER_NULL_CODENAME`,text:{KOREA:`죄, 죄송해요.`,JPN:`ご、ごめんなさい。`,ENG:`I-I'm sorry.`,TWN:`對、對不起。`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`EXOSUIT_FLOOR_NULL_TEAM3`,face:`UNIT_IDLE`},C:null,R:{char_id:`SAW_REAPER_NULL_CODENAME`,face:`UNIT_SURPRISE`}}}},{id:`L15_1`,type:`dialog`,speaker:`SPENCER_FLOOR_NULL_NULL`,text:{KOREA:`그만둬. 지금은 그런 걸로 싸울 때가 아니야.`,JPN:`やめて。今は揉めている場合じゃない。`,ENG:`Enough. Now's not the time for an argument.`,TWN:`夠了。現在不是爭論這些的時候。`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SPENCER_FLOOR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`EXOSUIT_FLOOR_NULL_TEAM2`,text:{KOREA:`느낌이 안 좋군. 서두르자고.`,JPN:`嫌な感じがする。急ごうぜ。`,ENG:`I have a bad feeling. Let's hurry.`,TWN:`我有一種不好的預感。趕緊走吧。`},stage:{bg:`FLOOR_FACILITY_01`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`EXOSUIT_FLOOR_NULL_TEAM2`,face:`UNIT_IDLE`},R:null}}}];export{e as default};